<template>
  <div class="centered-text">
      <h1 class="primary-header">{{title}}</h1>
      <h4 class="primary-sub-header">{{subtitle}}</h4>
    </div>
</template>

<script>
export default {
  name: 'Home',
  data () {
    return {
      title: 'Donovan J LaDuke',
      subtitle: 'Software Developer by Passion and Trade'
    }
  }
}
</script>

<style scoped>
.centered-text {
    height: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    text-align: center;
    flex-direction: column;
}

.primary-header {
    font-size: 6vw;
    margin: 0;
}

.primary-sub-header {
    font-size: 2vw;
    margin: 0;
}

@media (max-width: 800px) {
    .primary-header {
        font-size: 10vw;
    }

    .primary-sub-header {
        font-size: 4vw;
    }
}
</style>



