<template>
  <div id="app">
    <div class="drawer-wrapper">
    <transition name="fade">
    <div class="drawer-mask" v-if="isDrawerOpen" v-on:click="toggleDrawer"></div>
    </transition>
    <transition name="drawer">
    <div class="drawer" v-if="isDrawerOpen">
        <span class="drawer-header">Donovan J LaDuke</span>
        <nav class="drawer-links" v-on:click="toggleDrawer">
            <router-link to="/">Home</router-link>
            <router-link to="/About">About</router-link>
            <router-link to="/Contact">Contact</router-link>
        </nav>
    </div>
    </transition>
    </div>
    <header>
      <button class="hamburger-button" v-on:click="toggleDrawer">
        <svg height="24" viewBox="0 0 24 24" width="24" xmlns="http://www.w3.org/2000/svg">
        <path d="M0 0h24v24H0z" fill="none"/>
        <path d="M3 18h18v-2H3v2zm0-5h18v-2H3v2zm0-7v2h18V6H3z"/>
      </svg>
      </button>
      <span class="title">Donovan J LaDuke</span>
      <nav>
          <router-link to="/">Home</router-link>
          <router-link to="/About">About</router-link>
          <router-link to="/Contact">Contact</router-link>
      </nav>
    </header>
    <main>
      <transition name="slide" mode="out-in">
          <router-view></router-view>
      </transition>
    </main>
</div>
</template>

<script>
export default {
  name: 'app',
  data () {
    return {
      isDrawerOpen: false
    }
  },
  methods: {
    toggleDrawer: function(event) {
      this.isDrawerOpen = !this.isDrawerOpen;
    }
  }
}
</script>

<style lang="scss">
// CSS Reset
  html, body, #app {
    height: 100%;
  }

  html {
    box-sizing: border-box;
    font-size: 16px;
  }

  *, *:before, *:after {
    box-sizing: inherit;
  }

  * {
    margin: 0;
    padding: 0;
    font-weight: normal;
    box-sizing: inherit;
    line-height: 1;
    font-family: 'Open Sans', sans-serif;;
  }

  ol, ul {
    list-style: none;
  }

  img {
    max-width: 100%;
    height: auto;
  }
  // End CSS Reset

.slide-enter-active, .slide-leave-active {
  transition: transform .5s ease,
              opacity .5s ease;
}
.slide-enter {
  transform: translate(100px, 0);
  opacity: 0;
}

 .slide-leave-active {
  transform: translate(-100px, 0);
  opacity: 0;
}

header {
  display: grid;
  grid: '. .' / auto 1fr;
  align-items: center;
  grid-gap: 12px;
  
  @media (min-width: 800px) {
    grid: '. .' / 1fr auto;
    padding: 0 40px;
  }
  
  padding: 0 20px;
  position: fixed;
  right: 0;
  left: 0;
  height: 56px;
  box-shadow: 0 2px 2px 0 rgba(0,0,0,.14),0 3px 1px -2px rgba(0,0,0,.2),0 1px 5px 0 rgba(0,0,0,.12);
  z-index: 3;
  background-color: rgb(76,175,80);
  color: white;
  fill: white;

  .title {
      font-size: 16px;
  font-weight: 600;
  }

  nav {
    display: none;
    
    @media (min-width: 800px) {
      display: grid;
      grid: '. . .';
    }
    
    > * {
      color: inherit;
      text-decoration: none;
      height: 56px;
      line-height: 56px;
      padding: 0 12px;
    }
  }

  .hamburger-button {
      border: none;
      background: transparent;
      cursor: pointer;
      
      @media (min-width: 800px) {
        display: none;
      }
  }
}

main {
  padding: 12px;
  position: absolute;
  top: 56px;
  bottom: 0;
  right: 0;
  left: 0;
  overflow-x: hidden;
}

.drawer {
  display: flex;
  flex-direction: column;
  align-content: start;
  position: absolute;
  top: 0;
  width: 240px;
  bottom: 0;
  left: 0;
  background: white;
  box-shadow: 0 2px 2px 0 rgba(0,0,0,.14),0 3px 1px -2px rgba(0,0,0,.2),0 1px 5px 0 rgba(0,0,0,.12);
  z-index: 10;
  
  // animation: ${props => props.isOpen ? slideIn : slideOut} .25s linear forwards;
  // visibility: ${props => props.isOpen ? 'visible' : 'hidden'};
  // transition: all .25s linear;
  .drawer-header {
  font-size: 20px;
  font-weight: 600;
  padding: 24px;
  background: whitesmoke;
  }

  .drawer-links {
    display: flex;
    flex-direction: column;
    
    > * {
      text-decoration: none;
      color: dimgray;
      padding: 18px 12px;
      
      :hover {
        background: lightgray;
      }
    }
  }
}

.drawer-mask {
    position: fixed;
  top: 0;
  bottom: 0;
  right: 0;
  left: 0;
  z-index: 5;
  background: rgba(1,1,1,0.5);
  cursor: pointer;
}

.fade-enter-active, .fade-leave-active {
  transition: opacity .5s;
}
.fade-enter, .fade-leave-to {
  opacity: 0;
}

.drawer-enter-active, .drawer-leave-active {
  transition: transform .5s ease;
}
.drawer-enter, .drawer-leave-active {
  transform: translate(-240px, 0);
}

</style>



